from __future__ import annotations
from typing import TypedDict, NotRequired, Literal

# Anthropic message format
class TextBlock(TypedDict):
    type: Literal["text"]
    text: str

class ToolUseBlock(TypedDict):
    type: Literal["tool_use"]
    id: str
    name: str
    input: dict

ContentBlock = TextBlock | ToolUseBlock  # union type

class AnthropicMessage(TypedDict):
    role: Literal["user", "assistant"]
    content: str | list[ContentBlock]

# Build a conversation
def make_user_message(text: str) -> AnthropicMessage:
    return {"role": "user", "content": text}

def make_assistant_message(text: str) -> AnthropicMessage:
    return {"role": "assistant", "content": text}

# Type checker validates key access
messages: list[AnthropicMessage] = [
    make_user_message("What is 2+2?"),
    make_assistant_message("4"),
]

# This would be a type error if role wasn't declared:
# msg: AnthropicMessage = {"role": "system", "content": "x"}
# Error: "system" is not assignable to Literal["user", "assistant"]

from __future__ import annotations
from typing import TypedDict, NotRequired, Required

class AgentState(TypedDict):
    """State passed through an agent's execution loop."""
    run_id: str                              # always required
    messages: list[dict]                     # always required
    tool_results: dict[str, dict]            # always required
    last_error: NotRequired[str | None]      # may be absent; None = no error
    metadata: NotRequired[dict[str, str]]    # may be absent

def create_initial_state(run_id: str) -> AgentState:
    return {
        "run_id": run_id,
        "messages": [],
        "tool_results": {},
        # last_error and metadata are NotRequired — we can omit them
    }

def record_error(state: AgentState, error: str) -> AgentState:
    return {**state, "last_error": error}

state = create_initial_state("run-001")
print(state)
# {'run_id': 'run-001', 'messages': [], 'tool_results': {}}

state_with_error = record_error(state, "Tool timeout")
print(state_with_error.get("last_error"))  # 'Tool timeout'

# Accessing NotRequired field safely
if err := state_with_error.get("last_error"):
    print(f"Last error: {err}")

from __future__ import annotations
import json
from typing import TypedDict, cast

class SearchResult(TypedDict):
    id: str
    title: str
    url: str
    score: float

class SearchResponse(TypedDict):
    results: list[SearchResult]
    total: int
    query: str

def parse_search_response(raw_json: str) -> SearchResponse | None:
    """Parse a search API JSON response. Returns None on parse failure."""
    try:
        data = json.loads(raw_json)
    except json.JSONDecodeError:
        return None

    # Validate required keys are present
    if not all(key in data for key in ("results", "total", "query")):
        return None

    # cast: tells the type checker to treat data as SearchResponse
    # Use only after manual validation — cast is not a runtime check
    return cast(SearchResponse, data)

# Usage with narrowing
raw = '{"results": [{"id": "1", "title": "Paris", "url": "https://...", "score": 0.9}], "total": 1, "query": "capital of france"}'

if (resp := parse_search_response(raw)) is not None:
    print(f"Found {resp['total']} results for '{resp['query']}'")
    for r in resp["results"]:
        print(f"  {r['title']} ({r['score']:.2f})")

from __future__ import annotations
from typing import TypedDict

class ToolCallResult(TypedDict):
    tool_name: str
    output: dict | None
    error: str | None

def get_result_text(result: ToolCallResult) -> str:
    """Safely extract a text summary from a tool call result."""
    if result["error"] is not None:
        return f"Error: {result['error']}"

    output = result["output"]
    if output is None:
        return f"Tool {result['tool_name']} returned no output"

    # At this point output is dict (narrowed from dict | None)
    return str(output.get("text") or output.get("result") or output)

# Test
ok_result: ToolCallResult = {"tool_name": "search", "output": {"text": "Paris"}, "error": None}
err_result: ToolCallResult = {"tool_name": "search", "output": None, "error": "Timeout"}
null_result: ToolCallResult = {"tool_name": "search", "output": None, "error": None}

print(get_result_text(ok_result))    # 'Paris'
print(get_result_text(err_result))   # 'Error: Timeout'
print(get_result_text(null_result))  # 'Tool search returned no output'

from __future__ import annotations
from typing import TypedDict, Callable, Any

class ToolDef(TypedDict):
    name: str
    description: str
    function: Callable[..., dict[str, Any]]
    input_schema: dict[str, Any]

class ToolResult(TypedDict):
    tool_name: str
    output: dict[str, Any] | None
    error: str | None

REGISTRY: dict[str, ToolDef] = {}

def register(name: str, description: str, schema: dict[str, Any]):
    def decorator(fn: Callable[..., dict[str, Any]]):
        REGISTRY[name] = {
            "name": name,
            "description": description,
            "function": fn,
            "input_schema": schema,
        }
        return fn
    return decorator

@register(
    "get_weather",
    "Get current weather for a city",
    {"type": "object", "properties": {"city": {"type": "string"}}},
)
def get_weather(city: str) -> dict[str, Any]:
    return {"city": city, "temperature": 22, "condition": "sunny"}

def call_tool(name: str, **kwargs: Any) -> ToolResult:
    tool_def: ToolDef | None = REGISTRY.get(name)
    if tool_def is None:
        return {"tool_name": name, "output": None, "error": f"Unknown tool: {name}"}
    try:
        output = tool_def["function"](**kwargs)
        return {"tool_name": name, "output": output, "error": None}
    except Exception as exc:
        return {"tool_name": name, "output": None, "error": str(exc)}

result = call_tool("get_weather", city="Paris")
print(result)  # {'tool_name': 'get_weather', 'output': {...}, 'error': None}
